"""Simple arithmetic expression evaluator.
Supports: +, -, *, /, parentheses, unary minus, variables.
"""

def tokenize(expr):
    """Convert expression string to list of tokens."""
    tokens = []
    i = 0
    while i < len(expr):
        if expr[i].isspace():
            i += 1
        elif expr[i].isdigit() or expr[i] == '.':
            j = i
            while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                j += 1
            tokens.append(('NUM', float(expr[i:j])))
            i = j
        elif expr[i].isalpha():
            j = i
            while j < len(expr) and expr[j].isalnum():
                j += 1
            tokens.append(('VAR', expr[i:j]))
            i = j
        elif expr[i] in '+-*/()':
            tokens.append(('OP', expr[i]))
            i += 1
        else:
            raise SyntaxError(f"Unexpected character: {expr[i]}")
    return tokens

def evaluate(expr, variables=None):
    """Evaluate arithmetic expression string."""
    variables = variables or {}
    tokens = tokenize(expr)
    pos = [0]  # mutable index

    def parse_expr():
        """Handle + and - (lowest precedence)."""
        left = parse_term()
        while pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '+') or               pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '-'):
            op = tokens[pos[0]][1]
            pos[0] += 1
            right = parse_term()
            if op == '+':
                left = left + right
            else:
                left = left - right
        return left

    def parse_term():
        """Handle * and / (higher precedence)."""
        left = parse_factor()
        while pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '*') or               pos[0] < len(tokens) and tokens[pos[0]] == ('OP', '/'):
            op = tokens[pos[0]][1]
            pos[0] += 1
            right = parse_factor()
            if op == '*':
                left = left * right
            else:
                if right == 0:
                    raise ZeroDivisionError("Division by zero")
                left = left / right
        return left

    def parse_factor():
        """Handle unary minus, numbers, variables, parentheses."""
        if pos[0] >= len(tokens):
            raise SyntaxError("Unexpected end of expression")

        token = tokens[pos[0]]

        # Unary minus
        if token == ('OP', '-'):
            pos[0] += 1
            return -parse_factor()

        # Parenthesized expression
        if token == ('OP', '('):
            pos[0] += 1
            result = parse_expr()
            if pos[0] >= len(tokens) or tokens[pos[0]] != ('OP', ')'):
                raise SyntaxError("Missing closing parenthesis")
            pos[0] += 1
            return result

        # Number
        if token[0] == 'NUM':
            pos[0] += 1
            return token[1]

        # Variable
        if token[0] == 'VAR':
            pos[0] += 1
            name = token[1]
            if name not in variables:
                raise NameError(f"Undefined variable: {name}")
            return variables[name]

        raise SyntaxError(f"Unexpected token: {token}")

    result = parse_expr()
    if pos[0] < len(tokens):
        raise SyntaxError(f"Unexpected token after expression: {tokens[pos[0]]}")
    return result

